class Solution {
    public int getKth(int lo, int hi, int k) {
        int[][] powers = new int[hi - lo + 1][2];
        for (int i = lo; i <= hi; i++) {
            powers[i - lo][0] = i;
            powers[i - lo][1] = power(i);
        }
        Arrays.sort(powers, (a, b) -> a[1] == b[1] ? a[0] - b[0] : a[1] - b[1]);
        return powers[k - 1][0];
    }

    private int power(int x) {
        int count = 0;
        while (x != 1) {
            if (x % 2 == 0) {
                x /= 2;
            } else {
                x = 3 * x + 1;
            }
            count++;
        }
        return count;
    }
}
